// Phase 2 placeholder — Instagram scraping requires Graph API access from the venue
// or Claude AI-assisted caption parsing. Skipped for now.
const slug = $json.slug || 'unknown';
console.log('[venue-events-sync] SKIP ' + slug + ' instagram source — Phase 2 not yet implemented');
return [];

// Website scraping not yet wired — add HTTP Request + HTML Extract nodes here
// when venue website URLs are confirmed (Ruby's Elixir, Blueberry Patch).
const slug = $json.slug || 'unknown';
console.log('[venue-events-sync] SKIP ' + slug + ' website source — scraper not yet wired');
return [];

// Build the Graph API URL and pass venue context through.
// HTTP calls belong in HTTP Request nodes — this node only prepares data.
const item = $input.first().json;
const appId     = $env.FB_APP_ID;
const appSecret = $env.FB_APP_SECRET;
const pageId    = item.facebookPageId;

if (!pageId || !appId || !appSecret) {
  console.log('[venue-events-sync] ' + item.slug + ': missing FB_APP_ID, FB_APP_SECRET, or facebookPageId — skipping');
  return [];
}

const nowUnix = Math.floor(Date.now() / 1000);
const maxUnix = nowUnix + 60 * 24 * 60 * 60;
const token   = appId + '|' + appSecret;
const fields  = 'id,name,description,start_time,end_time,cover,ticket_uri,place';

const graphApiUrl = 'https://graph.facebook.com/v21.0/' + pageId + '/events'
  + '?access_token=' + encodeURIComponent(token)
  + '&fields=' + fields
  + '&since=' + nowUnix
  + '&until=' + maxUnix
  + '&limit=50';

return [{ json: { ...item, _graphApiUrl: graphApiUrl } }];

// Normalise Graph API response into the shape expected by Loop Over Events.
// Source context (slug, calendarId) retrieved from the URL-builder node because
// the HTTP Request node replaced $json with the API response body.
const sourceItem = $('FB: Build Graph API URL').first().json;
const response   = $input.first().json;

const slug       = sourceItem.slug;
const calendarId = sourceItem.googleCalendarId;

const events = response.data;
if (!events || !Array.isArray(events) || events.length === 0) {
  const reason = (response.error && response.error.message) ? response.error.message : 'empty or failed response';
  console.log('[venue-events-sync] ' + slug + ': Graph API returned no events — ' + reason);
  return [];
}

const now = Date.now();
const max = now + 60 * 24 * 60 * 60 * 1000;
const normalised = [];

for (const ev of events) {
  try {
    const startMs = ev.start_time ? new Date(ev.start_time).getTime() : null;
    if (!startMs || startMs < now || startMs > max) continue;
    const id = String(ev.id);
    normalised.push({ json: {
      _slug:       slug,
      _calendarId: calendarId,
      fbEventId:   id,
      dedup_id:    'fb_' + id,
      title:       ev.name        || '',
      description: ev.description || null,
      startTime:   ev.start_time,
      endTime:     ev.end_time    || null,
      imageUrl:    (ev.cover && ev.cover.source) ? ev.cover.source : null,
      ticketUrl:   ev.ticket_uri  || null,
      eventBy:     (ev.place && ev.place.name) ? ev.place.name : null,
      fbEventUrl:  'https://www.facebook.com/events/' + id,
      source:      'graph_api'
    }});
  } catch (e) {
    console.log('[venue-events-sync] ' + slug + ': error normalising event ' + ev.id + ' — ' + e.message);
  }
}

console.log('[venue-events-sync] ' + slug + ': normalised ' + normalised.length + ' events from graph_api');
return normalised;

// Check if the event already exists in GCal by matching dedup_id in description
// or by close title + date match (±12h).
const eventItem = $('Loop Over Events').first().json;
const gcalResults = $input.all();

const dedupId    = eventItem.dedup_id || '';
const eventTitle = (eventItem.title || '').toLowerCase().trim();
const eventStart = eventItem.startTime ? new Date(eventItem.startTime).getTime() : null;

let found = null;
for (const r of gcalResults) {
  const desc  = (r.json.description || '').toLowerCase();
  const title = (r.json.summary     || '').toLowerCase().trim();
  const start = (r.json.start && r.json.start.dateTime) ? new Date(r.json.start.dateTime).getTime() : null;

  if (dedupId && desc.includes('[dedup_id: ' + dedupId + ']')) { found = r.json; break; }
  if (eventTitle && title === eventTitle && eventStart && start) {
    if (Math.abs(eventStart - start) / (1000 * 60 * 60) <= 12) { found = r.json; break; }
  }
}

return [{
  json: {
    ...eventItem,
    _gcalExists:  found ? true : false,
    _gcalEventId: found ? found.id : null
  }
}];

// Build the GCal event description with structured metadata.
// The [dedup_id: fb_XXX] anchor is used by the duplicate-check node on future runs.
const ev = $input.first().json;

const parts = [];
if (ev.eventBy)    parts.push('Presented by: ' + ev.eventBy);
if (ev.ticketUrl)  parts.push('Tickets: ' + ev.ticketUrl);
if (ev.description) { parts.push('---'); parts.push(ev.description); }
parts.push('');
if (ev.fbEventUrl) parts.push('Source: ' + ev.fbEventUrl);
parts.push('[dedup_id: ' + ev.dedup_id + ']');

const description = parts.join('\n').trim();

function toRFC3339(str) {
  if (!str) return null;
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d.toISOString();
}

return [{ json: {
  ...ev,
  _gcalDescription: description,
  _startRFC: toRFC3339(ev.startTime),
  _endRFC:   ev.endTime ? toRFC3339(ev.endTime) : null
} }];

// Merge GCal event id from the create response back onto the event item.
const created  = $input.first().json;
const loopItem = $('Loop Over Events').first().json;
const gcalId   = created.id || loopItem._gcalEventId || null;

if (!gcalId) {
  console.log('[venue-events-sync] ' + loopItem._slug + ': could not get GCal event id — skipping DB upsert');
  return [];
}
return [{ json: { ...loopItem, _gcalEventId: gcalId } }];

// Already exists path — pass the existing GCal event id through.
const ev = $input.first().json;
if (!ev._gcalEventId) {
  console.log('[venue-events-sync] ' + ev._slug + ': already in GCal but no id — skipping DB upsert');
  return [];
}
return [{ json: ev }];

// Build the DB upsert SQL.
// Does NOT set tag — owned by spm-multi-gcal-to-db-sync tag detection.
function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

const ev = $input.first().json;
if (!ev._gcalEventId) return [];

const extraData = JSON.stringify({
  source:       ev.source       || 'facebook',
  fb_event_url: ev.fbEventUrl   || null,
  event_by:     ev.eventBy      || null,
  dedup_id:     ev.dedup_id     || null
});

const sql = 'INSERT INTO events (\n'
  + '  google_event_id, title, description, start_time, end_time,\n'
  + '  venue, ticket_url, image_url, extra_data, is_active, synced_at\n'
  + ') VALUES (\n'
  + '  ' + esc(ev._gcalEventId) + ',\n'
  + '  ' + esc(ev.title) + ',\n'
  + '  ' + esc(ev.description) + ',\n'
  + '  ' + (ev.startTime ? esc(ev.startTime) + '::TIMESTAMPTZ' : 'NULL') + ',\n'
  + '  ' + (ev.endTime   ? esc(ev.endTime)   + '::TIMESTAMPTZ' : 'NULL') + ',\n'
  + '  ' + esc(ev._slug) + ',\n'
  + '  ' + esc(ev.ticketUrl) + ',\n'
  + '  ' + esc(ev.imageUrl) + ',\n'
  + '  ' + esc(extraData) + '::jsonb,\n'
  + '  true,\n'
  + '  NOW()\n'
  + ')\n'
  + 'ON CONFLICT (google_event_id) DO UPDATE SET\n'
  + '  title       = EXCLUDED.title,\n'
  + '  description = EXCLUDED.description,\n'
  + '  start_time  = EXCLUDED.start_time,\n'
  + '  end_time    = EXCLUDED.end_time,\n'
  + '  venue       = EXCLUDED.venue,\n'
  + '  ticket_url  = EXCLUDED.ticket_url,\n'
  + '  image_url   = EXCLUDED.image_url,\n'
  + '  extra_data  = EXCLUDED.extra_data,\n'
  + '  is_active   = true,\n'
  + '  synced_at   = NOW()\n'
  + 'RETURNING id, google_event_id, title';

return [{ json: { sql, title: ev.title, slug: ev._slug } }];

// 300ms throttle between events to stay under GCal API quota.
await new Promise(function(r) { setTimeout(r, 300); });
return $input.all();

const cleaned = $input.all();
console.log('[venue-events-sync] RUN COMPLETE — images cleaned: ' + cleaned.length + ' — ' + new Date().toISOString());
return [{ json: { ok: true, images_cleaned: cleaned.length, finished_at: new Date().toISOString() } }];
